<div class="page-head"><h2>Google Drive Settings</h2><a class="btn btn-light" href="<?=url('/documents')?>">Documents</a></div>
<div class="card"><form method="post" action="<?=url('/settings/google-drive/save')?>"><?=csrf_field()?><div class="form-row"><div><label>Enable Google Drive</label><select name="gdrive_enabled"><option value="0">No</option><option value="1" <?=setting('gdrive_enabled')==='1'?'selected':''?>>Yes</option></select></div><div><label>Default Folder ID</label><input name="gdrive_default_folder_id" value="<?=e(setting('gdrive_default_folder_id'))?>"></div></div><div class="form-row"><div><label>CV Folder ID</label><input name="gdrive_cv_folder_id" value="<?=e(setting('gdrive_cv_folder_id'))?>"></div><div><label>Employee Document Folder ID</label><input name="gdrive_employee_doc_folder_id" value="<?=e(setting('gdrive_employee_doc_folder_id'))?>"></div></div><label>Supporting Files Folder ID</label><input name="gdrive_supporting_folder_id" value="<?=e(setting('gdrive_supporting_folder_id'))?>"><div class="form-row"><div><label>Google Client ID</label><input name="gdrive_client_id" value="<?=e(setting('gdrive_client_id'))?>"></div><div><label>Google Client Secret</label><input name="gdrive_client_secret" value="<?=e(setting('gdrive_client_secret'))?>"></div></div><label>Refresh Token</label><input name="gdrive_refresh_token" value="<?=e(setting('gdrive_refresh_token'))?>"><button class="btn btn-primary">Save Google Drive Settings</button></form></div>
